std::string Tests::exec()
{
    Materials::instance()->informObservers(false);
    BoundaryConditions::instance()->informObservers(false);

    std::ostringstream report;
    report<<"conducte\u00F6 [s] validation report"<<std::endl;
    report<<"*******************************"<<std::endl;
    report<<std::endl;

    std::string success=rotation();
    report<<"   rotations tests:               "<<success<<std::endl;

    success=lineIntersection();
    report<<"   lines inter. tests:            "<<success<<std::endl;

    success=splitCells();
    report<<"   split cells tests:             "<<success<<std::endl;

    success=translation();
    report<<"   translations tests:            "<<success<<std::endl;

    success=scaling();
    report<<"   scalings tests:                "<<success<<std::endl;

    success=closedVolume();
    report<<"   closed volumes tests:          "<<success<<std::endl;

    success=lineContainsPoint();
    report<<"   lines cont. pts tests:         "<<success<<std::endl;

    success=ellipsePointAtAngle();
    report<<"   ellipse pt @angle tests:       "<<success<<std::endl;

    success=volumeContainsPoint();
    report<<"   volume cont. pt tests:         "<<success<<std::endl;

    success=createSurfaces();
    report<<"   surfaces creation tests (1):   "<<success<<std::endl;

    success=createSurfaces2();
    report<<"   surfaces creation tests (2):   "<<success<<std::endl;

    success=createSurfaces3();
    report<<"   surfaces creation tests (3):   "<<success<<std::endl;

    success=createSurfaces4();
    report<<"   surfaces creation tests (4):   "<<success<<std::endl;

    success=circleLineIntersection();
    report<<"   circle line inter. tests:      "<<success<<std::endl;

    success=c2dSurfacesCreation();
    report<<"   c2d surfaces creation tests:   "<<success<<std::endl;

    success=en10211Tests();
    report<<"   EN 10211 tests:                "<<success<<std::endl;

    success=en10077Tests();
    report<<"   EN 10077-2 tests:              "<<success<<std::endl;

    success=pluginEn13370();
    report<<"   EN 13370 tests:                "<<success<<std::endl;

    success=psiCoefficients();
    report<<"   psi coefficients tests:        "<<success<<std::endl;

    Materials::instance()->informObservers(true);
    BoundaryConditions::instance()->informObservers(true);
    
    return report.str();
}

bool Tests::isEqual(double value, double reference, double precision) const
{
    double d=std::fabs(value-reference);
    if (d>precision)
        return false;
    return true;
}

std::string Tests::rotation()
{
    Rotation r;
    Point center;
    center.setX(0.5);
    center.setY(0.5);
    r.setCenter(center);
    r.setAngle(30.0);

    Point p1;
    p1.setX(1.2);
    p1.setY(0.8);

    // Test 1.
    Point p2=r.apply(p1);
    if (!isEqual(p2.x(), 0.956217, 1.0e-6))
        return "FAILED @test1:1";
    if (!isEqual(p2.y(), 1.109807, 1.0e-6))
        return "FAILED @test1:2";

    // Test 2.
    Point p3=r.applyInverse(p2);
    if (!isEqual(p3.x(), p1.x()))
        return "FAILED @test2:1";
    if (!isEqual(p3.y(), p1.y()))
        return "FAILED @test2:2";

    return "PASSED";
}

std::string Tests::translation()
{
    Point p1;
    p1.setX(1.2);
    p1.setY(0.8);

    Translation translation;
    translation.setHorizontalDistance(2.4);
    translation.setVerticalDistance(0.8);

    // Test 1.
    Point p2=translation.apply(p1);
    if (!isEqual(p2.x(), 3.6, 1.0e-6))
        return "FAILED @test1:1";
    if (!isEqual(p2.y(), 1.6, 1.0e-6))
        return "FAILED @test1:2";

    // Test 2.
    Point p3=translation.applyInverse(p2);
    if (!isEqual(p3.x(), p1.x()))
        return "FAILED @test2:1";
    if (!isEqual(p3.y(), p1.y()))
        return "FAILED @test2:2";

    return "PASSED";
}

std::string Tests::scaling()
{
    Point p1;
    p1.setX(1.2);
    p1.setY(0.8);

    Scaling scaling;
    scaling.setType((Scaling::Type) (Scaling::XScaling | Scaling::YScaling));
    scaling.setXScalingFactor(1.1);
    scaling.setYScalingFactor(9.7);

    // Test 1.
    Point p2=scaling.apply(p1);
    if (!isEqual(p2.x(), 1.32, 1.0e-6))
        return "FAILED @test1:1";
    if (!isEqual(p2.y(), 7.76, 1.0e-6))
        return "FAILED @test1:2";

    // Test 2.
    Point p3=scaling.applyInverse(p2);
    if (!isEqual(p3.x(), p1.x()))
        return "FAILED @test2:1";
    if (!isEqual(p3.y(), p1.y()))
        return "FAILED @test2:2";

    return "PASSED";
}

std::string Tests::closedVolume()
{
    Point p1;
    p1.setX(1.37);
    p1.setY(2.0/3.0);

    Point p2;
    p2.setX(2.4);
    p2.setY(2.0/3.0);

    Point p3;
    p3.setX(1.999);
    p3.setY(1.0);

    Volume volume;

    Line *line1=new Line;
    line1->setBegin(p1, 0);
    line1->setEnd(p2, 0);
    volume.push_back(line1);

    Line *line2=new Line;
    line2->setBegin(p2, 0);
    line2->setEnd(p3, 0);
    volume.push_back(line2);

    Line *line3=new Line;
    line3->setBegin(p3, 0);
    line3->setEnd(p1, 0);
    volume.push_back(line3);

    // Test 1.
    if (!volume.isClosed())
        return "FAILED @test1";

    Point p4;
    p4.setX(1.37);
    p4.setY(0.66);

    line3->setEnd(p4, 0);

    // Test 2.
    if (volume.isClosed())
        return "FAILED @test2";

    return "PASSED";
}

std::string Tests::lineIntersection()
{
    Point p1;
    p1.setX(2.0);
    p1.setY(1.0);

    Point p2;
    p2.setX(8.0);
    p2.setY(3.0);

    Point p3;
    p3.setX(2.0);
    p3.setY(3.0);

    Point p4;
    p4.setX(6.0);
    p4.setY(1.0);

    Line line1;
    line1.setBegin(p1, 0);
    line1.setEnd(p2, 0);

    Line line2;
    line2.setBegin(p3, 0);
    line2.setEnd(p4, 0);

    // Test 1.
    if (!GeometryTools::intersects(&line1, &line2))
        return "FAILED @test1:1";

    Point i=GeometryTools::intersectionPoint(&line1, &line2).at(0);
    if (!isEqual(i.x(), 4.4))
        return "FAILED @test1:2";
    if (!isEqual(i.y(), 1.8))
        return "FAILED @test1:3";

    p1.setX(1.0);
    p1.setY(1.0);

    p2.setX(6.0);
    p2.setY(5.0);

    p3.setX(3.0);
    p3.setY(1.0);

    p4.setX(5.0);
    p4.setY(3.0);

    line1.setBegin(p1, 0);
    line1.setEnd(p2, 0);

    line2.setBegin(p3, 0);
    line2.setEnd(p4, 0);

    // Test 2.
    if (GeometryTools::intersects(&line1, &line2))
        return "FAILED @test2:1";

    p1.setX(1.0);
    p1.setY(3.0);

    p2.setX(5.0);
    p2.setY(3.0);

    p3.setX(4.0);
    p3.setY(1.0);

    p4.setX(4.0);
    p4.setY(5.0);

    line1.setBegin(p1, 0);
    line1.setEnd(p2, 0);

    line2.setBegin(p3, 0);
    line2.setEnd(p4, 0);

    // Test 3.
    if (!GeometryTools::intersects(&line1, &line2))
        return "FAILED @test3:1";

    i=GeometryTools::intersectionPoint(&line1, &line2).at(0);
    if (!isEqual(i.x(), 4.0))
        return "FAILED @test3:2";
    if (!isEqual(i.y(), 3.0))
        return "FAILED @test3:3";

    p1.setX(1.0);
    p1.setY(3.0);

    p2.setX(4.0);
    p2.setY(3.0);

    p3.setX(6.0);
    p3.setY(1.0);

    p4.setX(6.0);
    p4.setY(5.0);

    line1.setBegin(p1, 0);
    line1.setEnd(p2, 0);

    line2.setBegin(p3, 0);
    line2.setEnd(p4, 0);

    // Test 4.
    if (GeometryTools::intersects(&line1, &line2))
        return "FAILED @test4:1";

    p1.setX(1.0);
    p1.setY(3.0);

    p2.setX(5.0);
    p2.setY(3.0);

    p3.setX(5.0);
    p3.setY(3.0);

    p4.setX(5.0);
    p4.setY(1.0);

    line1.setBegin(p1, 0);
    line1.setEnd(p2, 0);

    line2.setBegin(p3, 0);
    line2.setEnd(p4, 0);

    // Test 5.
    if (!GeometryTools::intersects(&line1, &line2))
        return "FAILED @test5:1";

    p1.setX(1.0);
    p1.setY(3.0);

    p2.setX(6.0);
    p2.setY(3.0);

    p3.setX(3.0);
    p3.setY(3.0);

    p4.setX(4.0);
    p4.setY(3.0);

    line1.setBegin(p1, 0);
    line1.setEnd(p2, 0);

    line2.setBegin(p3, 0);
    line2.setEnd(p4, 0);

    // Test 6.
    if (!GeometryTools::intersects(&line1, &line2))
        return "FAILED @test6:1";

    p1.setX(-0.22574263096700944);
    p1.setY(1.2802500789158704);

    p2.setX(-0.054446683406222940);
    p2.setY(0.30878248574019224);

    p3.setX(-2.2898349882893854e-016);
    p3.setY(6.6613381477509392e-016);

    p4.setX(0.069459271066772132);
    p4.setY(-0.39392310120488322);

    line1.setBegin(p1, 0);
    line1.setEnd(p2, 0);

    line2.setBegin(p3, 0);
    line2.setEnd(p4, 0);

    // Test 7.
    if (GeometryTools::intersects(&line1, &line2))
        return "FAILED @test7:1";

    return "PASSED";
}

std::string Tests::lineContainsPoint()
{
    Point p1;
    p1.setX(1.0);
    p1.setY(1.0);

    Point p2;
    p2.setX(6.0);
    p2.setY(5.0);

    Line line;
    line.setBegin(p1, 0);
    line.setEnd(p2, 0);

    Point p;
    p.setX(0.5);
    p.setY(0.5);

    // Test 1.
    if (GeometryTools::containsPoint(&line, p))
        return "FAILED @test1";

    p.setX(4.0);
    p.setY(1.0);

    // Test 2.
    if (GeometryTools::containsPoint(&line, p))
        return "FAILED @test2";

    p.setX(4.5);
    p.setY(2.6);

    // Test 3.
    if (GeometryTools::containsPoint(&line, p))
        return "FAILED @test3";

    p.setX(6.0);
    p.setY(5.0);

    // Test 4.
    if (!GeometryTools::containsPoint(&line, p))
        return "FAILED @test4";

    p.setX(3.0);
    p.setY(13.0/5.0);

    // Test 5.
    if (!GeometryTools::containsPoint(&line, p))
        return "FAILED @test5";

    return "PASSED";
}

std::string Tests::ellipsePointAtAngle()
{
    // Test 1.
    Point p=GeometryTools::ellipsePointAtAngle(8.0, 4.0, -45.0);
    if (!isEqual(p.x(), 3.5777087639996621, 1.0e-6))
        return "FAILED @test1:1";
    if (!isEqual(p.y(), -3.5777087639996639, 1.0e-6))
        return "FAILED @test1:2";

    // Test 2.
    p=GeometryTools::ellipsePointAtAngle(8.0, 4.0, -30.0);
    if (!isEqual(p.x(), 5.2372293656638140, 1.0e-6))
        return "FAILED @test2:1";
    if (!isEqual(p.y(), -3.0237157840738194, 1.0e-6))
        return "FAILED @test2:2";

    // Test 3.
    p=GeometryTools::ellipsePointAtAngle(8.0, 4.0, 0.0);
    if (!isEqual(p.x(), 8.0, 1.0e-6))
        return "FAILED @test3:1";
    if (!isEqual(p.y(), 0.0, 1.0e-6))
        return "FAILED @test3:2";

    // Test 4.
    p=GeometryTools::ellipsePointAtAngle(8.0, 4.0, 10.0);
    if (!isEqual(p.x(), 7.5446025031547812, 1.0e-6))
        return "FAILED @test4:1";
    if (!isEqual(p.y(), 1.3303169800268098, 1.0e-6))
        return "FAILED @test4:2";

    // Test 5.
    p=GeometryTools::ellipsePointAtAngle(8.0, 4.0, 30.0);
    if (!isEqual(p.x(), 5.2372293656638176, 1.0e-6))
        return "FAILED @test5:1";
    if (!isEqual(p.y(), 3.0237157840738176, 1.0e-6))
        return "FAILED @test5:2";

    // Test 6.
    p=GeometryTools::ellipsePointAtAngle(8.0, 4.0, 45.0);
    if (!isEqual(p.x(), 3.5777087639996639, 1.0e-6))
        return "FAILED @test6:1";
    if (!isEqual(p.y(), 3.5777087639996634, 1.0e-6))
        return "FAILED @test6:2";

    // Test 7.
    p=GeometryTools::ellipsePointAtAngle(8.0, 4.0, 80.0);
    if (!isEqual(p.x(), 0.70258269052444478, 1.0e-6))
        return "FAILED @test7:1";
    if (!isEqual(p.y(), 3.9845444395493770, 1.0e-6))
        return "FAILED @test7:2";

    // Test 8.
    p=GeometryTools::ellipsePointAtAngle(8.0, 4.0, 90.0);
    if (!isEqual(p.x(), 0.0, 1.0e-6))
        return "FAILED @test8:1";
    if (!isEqual(p.y(), 4.0, 1.0e-6))
        return "FAILED @test8:2";

    // Test 9.
    p=GeometryTools::ellipsePointAtAngle(8.0, 4.0, 120.0);
    if (!isEqual(p.x(), -2.2188007849009153, 1.0e-6))
        return "FAILED @test9:1";
    if (!isEqual(p.y(), 3.8430756913220914, 1.0e-6))
        return "FAILED @test9:2";

    // Test 10.
    p=GeometryTools::ellipsePointAtAngle(8.0, 4.0, 133.33);
    if (!isEqual(p.x(), -3.4127871142380752, 1.0e-6))
        return "FAILED @test10:1";
    if (!isEqual(p.y(), 3.6177646452226044, 1.0e-6))
        return "FAILED @test10:2";

    // Test 11.
    p=GeometryTools::ellipsePointAtAngle(8.0, 4.0, 180.0);
    if (!isEqual(p.x(), -8.0, 1.0e-6))
        return "FAILED @test11:1";
    if (!isEqual(p.y(), 0.0, 1.0e-6))
        return "FAILED @test11:2";

    // Test 12.
    p=GeometryTools::ellipsePointAtAngle(8.0, 4.0, 210.0);
    if (!isEqual(p.x(), -5.2372293656638167, 1.0e-6))
        return "FAILED @test12:1";
    if (!isEqual(p.y(), -3.0237157840738185, 1.0e-6))
        return "FAILED @test12:2";

    // Test 13.
    p=GeometryTools::ellipsePointAtAngle(8.0, 4.0, 330.0);
    if (!isEqual(p.x(), 5.2372293656638140, 1.0e-6))
        return "FAILED @test13:1";
    if (!isEqual(p.y(), -3.0237157840738194, 1.0e-6))
        return "FAILED @test13:2";

    // Test 14.
    p=GeometryTools::ellipsePointAtAngle(8.0, 4.0, 360.0);
    if (!isEqual(p.x(), 8.0, 1.0e-6))
        return "FAILED @test14:1";
    if (!isEqual(p.y(), 0.0, 1.0e-6))
        return "FAILED @test14:2";

    // Test 15.
    p=GeometryTools::ellipsePointAtAngle(8.0, 4.0, 400.0);
    if (!isEqual(p.x(), 4.0951115001699838, 1.0e-6))
        return "FAILED @test15:1";
    if (!isEqual(p.y(), 3.4362065494224709, 1.0e-6))
        return "FAILED @test15:2";

    return "PASSED";
}

std::string Tests::volumeContainsPoint()
{
    Volume volume;

    Point begin;
    Point end;

    begin.setX(2.0);
    begin.setY(1.0);
    end.setX(5.0);
    end.setY(1.0);

    Line *line=new Line;
    line->setBegin(begin, 0);
    line->setEnd(end, 0);
    volume.push_back(line);

    begin.setX(5.0);
    begin.setY(1.0);
    end.setX(5.0);
    end.setY(4.0);

    line=new Line;
    line->setBegin(begin, 0);
    line->setEnd(end, 0);
    volume.push_back(line);

    begin.setX(5.0);
    begin.setY(4.0);
    end.setX(2.0);
    end.setY(4.0);

    line=new Line;
    line->setBegin(begin, 0);
    line->setEnd(end, 0);
    volume.push_back(line);

    begin.setX(2.0);
    begin.setY(4.0);
    end.setX(2.0);
    end.setY(1.0);

    line=new Line;
    line->setBegin(begin, 0);
    line->setEnd(end, 0);
    volume.push_back(line);
    volume.computeBounds();

    // Test 1.
    if (!volume.isClosed())
        return "FAILED @test1:1";
    if (volume.isSelfIntersected())
        return "FAILED @test1:2";

    Point p;
    p.setX(6.0);
    p.setY(4.0);

    // Test 2.
    if (volume.containsPoint(p))
        return "FAILED @test2";

    p.setX(11.0);
    p.setY(6.0);

    // Test 3.
    if (volume.containsPoint(p))
        return "FAILED @test3";

    p.setX(4.0);
    p.setY(3.0);

    // Test 4.
    if (!volume.containsPoint(p))
        return "FAILED @test4";

    p.setX(3.5);
    p.setY(2.5);

    // Test 5.
    if (!volume.containsPoint(p))
        return "FAILED @test5";

    Volume volume2;

    begin.setX(-4.0);
    begin.setY(0.0);
    end.setX(-4.0);
    end.setY(4.0);

    line=new Line;
    line->setBegin(begin, 0);
    line->setEnd(end, 0);
    volume2.push_back(line);

    Arc *arc=new Arc;
    Point c;
    c.setX(-2.5);
    c.setY(4.0);
    arc->setCenter(c);
    arc->setHorizontalRadius(1.5, 0);
    arc->setVerticalRadius(1.5, 0);
    arc->setAngle(0.0, 180.0, 0);
    arc->recreateLines();
    volume2.push_back(arc);

    begin.setX(-1.0);
    begin.setY(4.0);
    end.setX(-1.0);
    end.setY(-2.0);

    line=new Line;
    line->setBegin(begin, 0);
    line->setEnd(end, 0);
    volume2.push_back(line);

    begin.setX(-1.0);
    begin.setY(-2.0);
    end.setX(-2.0);
    end.setY(0.0);

    line=new Line;
    line->setBegin(begin, 0);
    line->setEnd(end, 0);
    volume2.push_back(line);

    begin.setX(-2.0);
    begin.setY(0.0);
    end.setX(-2.0);
    end.setY(2.0);

    line=new Line;
    line->setBegin(begin, 0);
    line->setEnd(end, 0);
    volume2.push_back(line);

    arc=new Arc;
    c.setX(-2.5);
    c.setY(2.0);
    arc->setCenter(c);
    arc->setHorizontalRadius(0.5, 0);
    arc->setVerticalRadius(0.5, 0);
    arc->setAngle(0.0, 180.0, 0);
    arc->recreateLines();
    volume2.push_back(arc);

    begin.setX(-3.0);
    begin.setY(2.0);
    end.setX(-3.0);
    end.setY(-2.0);

    line=new Line;
    line->setBegin(begin, 0);
    line->setEnd(end, 0);
    volume2.push_back(line);

    begin.setX(-3.0);
    begin.setY(-2.0);
    end.setX(-4.0);
    end.setY(0.0);

    line=new Line;
    line->setBegin(begin, 0);
    line->setEnd(end, 0);
    volume2.push_back(line);
    volume2.computeBounds();

    // Test 6.
    if (!volume2.isClosed())
        return "FAILED @test6:1";
    if (volume2.isSelfIntersected())
        return "FAILED @test6:2";

    p.setX(0.0);
    p.setY(-2.0);

    // Test 7.
    if (volume2.containsPoint(p))
        return "FAILED @test7";

    p.setX(-5.0);
    p.setY(-1.0);

    // Test 8.
    if (volume2.containsPoint(p))
        return "FAILED @test8";

    p.setX(-2.5);
    p.setY(0.0);

    // Test 9.
    if (volume2.containsPoint(p))
        return "FAILED @test9";

    p.setX(-3.5);
    p.setY(0.0);

    // Test 10.
    if (!volume2.containsPoint(p))
        return "FAILED @test10";

    p.setX(-2.5);
    p.setY(4.0);

    // Test 11.
    if (!volume2.containsPoint(p))
        return "FAILED @test11";

    return "PASSED";
}

bool Tests::containsLine(const std::vector<Surface*> &surfaces, double x0, double y0, double x1, double y1) const
{
    Point p1;
    Point p2;

    p1.setX(x0);
    p1.setY(y0);
    p2.setX(x1);
    p2.setY(y1);

    for (unsigned int i=0 ; i<surfaces.size() ; i++)
    {
        Surface *s=surfaces.at(i);

        for (unsigned int j=0 ; j<s->size() ; j++)
        {
            Line *line=s->at(j);
            if (GeometryTools::pointDistance(line->begin(), p1)<1.0e-12 && GeometryTools::pointDistance(line->end(), p2)<1.0e-12)
                return true;
            if (GeometryTools::pointDistance(line->begin(), p2)<1.0e-12 && GeometryTools::pointDistance(line->end(), p1)<1.0e-12)
                return true;
        }
    }
    return false;
}

bool Tests::containsPath(const std::vector<Surface*> &surfaces, Path *ref) const
{
    for (unsigned int i=0 ; i<surfaces.size() ; i++)
    {
        Surface *s=surfaces.at(i);

        for (unsigned int j=0 ; j<s->size() ; j++)
        {
            Line *line=s->at(j);
            if (line->isEquivalentTo(ref))
                return true;
        }
    }
    return false;
}

bool Tests::surfacesAreEquivalent(const std::vector<Surface*> &surfaces1, const std::vector<Surface*> &surfaces2) const
{
    for (unsigned int i=0 ; i<surfaces1.size() ; i++)
    {
        Surface *s=surfaces1.at(i);
        for (unsigned int j=0 ; j<s->size() ; j++)
        {
            Line *line=s->at(j);
            if (!containsPath(surfaces2, line))
                return false;
        }
    }
    return true;
}

