std::string Tests::circleLineIntersection()
{
    Point p;
    p.setX(-0.6);
    p.setY(0.34);

    Arc arc;
    arc.setCenter(p);
    arc.setHorizontalRadius(0.4, 0);
    arc.setVerticalRadius(0.4, 0);
    arc.setAngle(0.0, 360.0, 0);
    arc.recreateLines();
    
    Line line;
    p.setX(-1.45);
    p.setY(0.128);
    line.setBegin(p, 0);

    p.setX(0.703);
    p.setY(0.128);
    line.setEnd(p, 0);

    // Test 1.
    if (!GeometryTools::intersects(&line, &arc))
        return "FAILED @test1";

    p.setX(-1.33);
    p.setY(0.4);
    line.setBegin(p, 0);

    p.setX(-0.9);
    p.setY(0.4);
    line.setEnd(p, 0);

    // Test 2.
    if (!GeometryTools::intersects(&line, &arc))
        return "FAILED @test2";

    p.setX(-0.9);
    p.setY(0.4);
    line.setBegin(p, 0);

    p.setX(-0.9);
    p.setY(0.615);
    line.setEnd(p, 0);

    // Test 3.
    if (!GeometryTools::intersects(&line, &arc))
        return "FAILED @test3";
    
    return "PASSED";
}

bool Tests::compareModelSurfacesCreation(const std::string &xml) const
{
    Model model1a;
    model1a.fromXml(xml, 0, false);

    Model model1b;
    model1b.fromXml(xml, 0);

    return surfacesAreEquivalent(model1a, model1b);
}

