bool Tests::comparePsiCoefficient(const std::string &xml, double psi, double precision) const
{
    Model model;
    model.fromXml(xml, 0);

    model.compute(0, false);
    double psi_value=model.psiCoefficient();

    double delta=std::fabs(psi_value-psi);

    return (delta<=precision);
}

double Tests::readPsiCoefficient(const std::string &xml) const
{
    Model model;
    model.fromXml(xml, 0);

    model.compute(0, false);
    return model.psiCoefficient();
}

bool Tests::comparePsiCoefficient(const std::string &xml, const std::string &env1, const std::string &env2, double psi, double precision) const
{
    Model model;
    model.fromXml(xml, 0);

    model.compute(0, true);
    std::vector<EnvironmentResult> envs=model.environmentResults();
    
    double psi_value=0.0;
    for (unsigned int i=0 ; i<envs.size() ; i++)
    {
        EnvironmentResult &env=envs.at(i);
        if (env._environment1Id==env1 && env._environment2Id==env2)
            psi_value=env._couplingCoefficient;
        if (env._environment1Id==env2 && env._environment2Id==env1)
            psi_value=env._couplingCoefficient;
    }

    double delta=std::fabs(psi_value-psi);
    return (delta<=precision);
}

