bool Tests::checkTemperature(Model *model, double x, double y, double reference, double precision) const
{
    bool success=false;
    double T=model->temperatureAtPosition(x, y, &success);

    if (!success)
        return false;

    double delta=std::fabs(reference-T);
    return (delta<=precision);
}

double Tests::readTemperature(Model *model, double x, double y) const
{
    bool success=false;
    return model->temperatureAtPosition(x, y, &success);
}

double Tests::readFlux(Model *model, double x, double y) const
{
    Surface *surface=model->getSurfaceAtPosition(x, y, 0.001);
    if (!surface)
        return 0.0;

    return surface->flux();
}

bool Tests::checkFlux(Model *model, double x, double y, double reference, double precision) const
{
    Surface *surface=model->getSurfaceAtPosition(x, y, 0.001);
    if (!surface)
        return false;

    double flux=surface->flux();

    double delta=std::fabs(reference-flux);
    return (delta<=precision);
}

Line *createLine(double x0, double y0, double x1, double y1)
{
    Line *line=new Line;
    
    Point begin;
    begin.setX(x0);
    begin.setY(y0);

    Point end;
    end.setX(x1);
    end.setY(y1);

    line->setBegin(begin, 0);
    line->setEnd(end, 0);

    return line;
}

std::string Tests::splitCells()
{
    std::vector<Line*> lines;
    lines.push_back(createLine(0.0, 0.0, 1.0, 0.0));
    lines.push_back(createLine(1.0, 0.0, 1.0, 1.0));
    lines.push_back(createLine(1.0, 1.0, 0.0, 1.0));
    lines.push_back(createLine(0.0, 1.0, 0.0, 0.0));

    lines.push_back(createLine(1.5, 1.5, 2.0, 1.5));
    lines.push_back(createLine(2.0, 1.5, 2.0, 2.0));
    lines.push_back(createLine(2.0, 2.0, 1.5, 2.0));
    lines.push_back(createLine(1.5, 2.0, 1.5, 1.5));

    Model m;
    Cell c;
    std::vector<Cell*> cells=m.createCellsFromLines(&c, lines);
    if (cells.size()!=2)
        return "FAILED @test1";

    std::vector<Line*> lines2;
    lines2.push_back(createLine(0.0, 0.0, 1.0, 0.0));
    lines2.push_back(createLine(1.0, 0.0, 1.0, 1.0));
    lines2.push_back(createLine(1.0, 1.0, 0.0, 1.0));
    lines2.push_back(createLine(0.0, 1.0, 0.0, 0.0));

    cells=m.createCellsFromLines(&c, lines2);
    if (cells.size()!=1)
        return "FAILED @test2";

    std::vector<Line*> lines3;
    lines3.push_back(createLine(0.0, 1.0, 0.0, 0.2));
    lines3.push_back(createLine(1.0, 0.7, 1.0, 1.0));
    lines3.push_back(createLine(0.0, 1.0, 1.0, 1.0));
    lines3.push_back(createLine(0.0, 0.2, 0.3, 0.35));
    lines3.push_back(createLine(0.6, 0.5, 0.8, 0.6));
    lines3.push_back(createLine(1.0, 0.7, 0.8, 0.6));
    lines3.push_back(createLine(0.6, 0.5, 0.3, 0.35));

    cells=m.createCellsFromLines(&c, lines3);
    if (cells.size()!=1)
        return "FAILED @test3";

    return "PASSED";
}

