std::string Tests::pluginEn13370()
{
    En13370Plugin plugin;
    
    // Example 1.
    plugin.setWallThickness(0.3);
    plugin.setGroundConductivity(1.5);
    plugin.setFloorResistance(0.0);
    plugin.setFloorExternalSuperficialResistance(0.04);
    plugin.setFloorInternalSuperficialResistance(0.17);
    plugin.setFloorWidth(5.676);
    plugin.setModelFloorWidth(1.0);
    plugin.setExternalTemperature(0.0);
    plugin.setInternalTemperature(1.0);
    plugin.setType(En13370Plugin::Median);

    double Hg=plugin.flux()*210.0;
    if (std::fabs(Hg-116.1)>0.1)
        return "FAILED @test1";

    // Example 2.
    plugin.setWallThickness(0.3);
    plugin.setGroundConductivity(2.0);
    plugin.setFloorResistance(0.0);
    plugin.setFloorExternalSuperficialResistance(0.04);
    plugin.setFloorInternalSuperficialResistance(0.17);
    plugin.setFloorWidth(3.789);
    plugin.setModelFloorWidth(1.0);
    plugin.setExternalTemperature(0.0);
    plugin.setInternalTemperature(1.0);
    plugin.setType(En13370Plugin::Median);

    double U=plugin.flux();
    if (std::fabs(U-0.91)>0.1)
        return "FAILED @test2:1";

    plugin.includeVerticalInsulation(true);
    plugin.setVerticalInsulationThickness(0.3);
    plugin.setInsulationHeight(0.6);
    plugin.setVerticalInsulationResistance(1.2);

    U=plugin.flux();
    if (std::fabs(U-0.70)>0.1)
        return "FAILED @test2:2";

    plugin.includeVerticalInsulation(false);
    plugin.setFloorResistance(0.625);

    U=plugin.flux();
    if (std::fabs(U-0.56)>0.1)
        return "FAILED @test2:3";

    plugin.setFloorResistance(2.5);

    U=plugin.flux();
    if (std::fabs(U-0.27)>0.1)
        return "FAILED @test2:4";

    plugin.includeVerticalInsulation(true);
    plugin.includeHorizontalInsulation(true);
    plugin.setHorizontalInsulationThickness(0.075);
    plugin.setInsulationWidth(0.6);
    plugin.setInsulationHeight(0.5);
    plugin.setVerticalInsulationResistance(1.5);
    plugin.setHorizontalInsulationResistance(1.5);

    U=plugin.flux();
    if (std::fabs(U-0.25)>0.1)
        return "FAILED @test2:5";

    // Example 3.
    plugin.setType(En13370Plugin::CrawlSpace);
    plugin.includeVerticalInsulation(false);
    plugin.includeHorizontalInsulation(false);
    plugin.setWindSpeed(4.0);
    plugin.setWindProtectionFactor(0.05);
    plugin.setOpeningsRatio(0.002);
    plugin.setGroundConductivity(1.5);
    plugin.setCrawlHeight(0.3);
    plugin.setFloorWidth(4.271);
    plugin.setFloorResistance(0.0);
    plugin.setZoneCeilResistance(0.5);
    plugin.setExternalWallResistance(1.0/1.7);

    U=plugin.flux();
    if (std::fabs(U-0.69)>0.1)
        return "FAILED @test3:1";

    plugin.setExternalWallResistance(2.0);

    U=plugin.flux();
    if (std::fabs(U-0.61)>0.1)
        return "FAILED @test3:2";

    plugin.setExternalWallResistance(1.0/1.7);
    plugin.setZoneCeilResistance(2.0);

    U=plugin.flux();
    if (std::fabs(U-0.34)>0.1)
        return "FAILED @test3:3";

    // Example 4.
    plugin.setType(En13370Plugin::HeatedUnderground);
    plugin.setFloorWidth(4.286);
    plugin.setUndergroundDepth(2.5);
    plugin.setGroundConductivity(2.0);
    plugin.setWallExternalSuperficialResistance(0.04);
    plugin.setWallInternalSuperficialResistance(0.13);
    plugin.setWallResistance(1.605);
    plugin.setModelFloorWidth(4.286);

    U=plugin.flux()/(4.286+2.5);
    if (std::fabs(U-0.41)>0.1)
        return "FAILED @test4";

    return "PASSED";
}
